from langchain.tools import BaseTool
from pydantic import BaseModel, Field
from typing import Optional

class OrderLookupInput(BaseModel):
    order_id: str = Field(description='Customer order ID')

class OrderLookupTool(BaseTool):
    name = 'order_lookup'
    description = 'Lookup order status by ID'
    args_schema = OrderLookupInput

    def _run(self, order_id: str) -> str:
        # Mock CRM API
        orders = {'12345': 'Shipped 2024-01-15', '67890': 'Pending payment'}
        return orders.get(order_id, 'Order not found')

order_tool = OrderLookupTool()
result = order_tool.run('12345')  # 'Shipped 2024-01-15'

import { OpenAIEmbeddings } from '@langchain/openai';
import { FAISS } from '@langchain/community/vectorstores/faiss';
import { RetrievalQAChain } from 'langchain/chains';
import { OpenAI } from '@langchain/openai';

const embeddings = new OpenAIEmbeddings();
const vectorStore = await FAISS.load(
  './support_kb',
  embeddings,
  { embeddings }
);

const llm = new OpenAI({ modelName: 'gpt-4' });
const chain = RetrievalQAChain.fromLLM(llm, vectorStore.asRetriever());

const response = await chain.call({
  query: 'How do I reset my password?'
});
