import { verify } from 'vex-sdk';

const safeAgent = async (query: string, history: string[]) => {
  const checks = [
    'response_accuracy',
    'pii_filtering',
    'policy_compliance',
    'escalation_triggers'
  ];

  const result = await verify(
    async () => {
      return await agent.call({ input: query, chatHistory: history });
    },
    {
      checks,
      riskProfile: 'high',
      escalationThreshold: 0.8
    }
  );

  return result.output;
};

